class Solution {
public:
    vector<int> earliestAndLatest(int n, int firstPlayer, int secondPlayer) {
        int earliest = earliestRound(n, firstPlayer, secondPlayer);
        int latest = latestRound(n, firstPlayer, secondPlayer);
        return {earliest, latest};
    }

    int earliestRound(int n, int firstPlayer, int secondPlayer) {
        int round = 1;
        while (firstPlayer != secondPlayer) {
            firstPlayer = (firstPlayer + 1) / 2;
            secondPlayer = (secondPlayer + 1) / 2;
            round++;
        }
        return round;
    }

    int latestRound(int n, int firstPlayer, int secondPlayer) {
        int round = 1;
        int left = 1, right = n;
        while (left <= right) {
            if (firstPlayer <= right && secondPlayer >= left) {
                left = (left + right + 1) / 2;
                right = (left + right) / 2;
                round++;
            } else {
                if (firstPlayer > right) firstPlayer -= (right - left + 1) / 2;
                if (secondPlayer < left) secondPlayer += (right - left + 1) / 2;
                left = (left + right) / 2;
                right = (left + right - 1) / 2;
                round++;
            }
        }
        return round;
    }
};
```
